// Compare mlllm linear attention pipeline against HF reference for Qwen3.5 layer 0.
// Input: tokens [1,2,3,4], seq_len=4
// Reference: /tmp/qwen35_ref_*.f32 (generated by dump_qwen35_ref.py)
//
// Steps compared:
//   1. x_normed (input RMSNorm) — just load ref, skip (tested elsewhere)
//   2. mixed_qkv = matmul(x_normed, in_proj_qkv_weight)
//   3. conv_out = shortconv(mixed_qkv, conv1d_weight)  [no conv_state]
//   4. split q,k,v
//   5. g = -exp(A_log) * softplus(a + dt_bias)
//   6. beta = sigmoid(b)
//   7. GDN recurrence (q, k, v, g, beta, state=0) → core_attn_out
//   8. normed_gated = rms_norm(core_attn_out, norm_weight) * silu(z)
//   9. output = matmul(normed_gated, out_proj_weight)

#include "kernels/matmul.h"
#include "kernels/norm.h"
#include "kernels/gdn.h"
#include "graph/graph.h"
#include "kernels/tensor.h"
#include "kernels/threading.h"
#include <cmath>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>

static int failures = 0;

static float* load_f32(const char* path, int expected_count) {
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "Cannot open %s\n", path); return nullptr; }
    float* data = new float[expected_count];
    size_t n = fread(data, sizeof(float), expected_count, f);
    fclose(f);
    if ((int)n != expected_count) {
        fprintf(stderr, "Short read %s: got %zu expected %d\n", path, n, expected_count);
        delete[] data;
        return nullptr;
    }
    return data;
}

static bool compare(const float* a, const float* b, int n, const char* name, float tol = 1e-3) {
    float max_err = 0;
    int max_idx = 0;
    for (int i = 0; i < n; i++) {
        float err = fabsf(a[i] - b[i]);
        if (err > max_err) { max_err = err; max_idx = i; }
    }
    if (max_err > tol) {
        fprintf(stderr, "  MISMATCH %s: max_err=%e at idx %d (ref=%f got=%f)\n", name, max_err, max_idx, a[max_idx], b[max_idx]);
        failures++;
        return false;
    }
    printf("  PASS: %s (max_err=%e at idx %d)\n", name, max_err, max_idx);
    return true;
}

int main() {
    const int hidden = 1024;
    const int seq_len = 4;
    const int num_heads = 16;
    const int k_dim = 128;
    const int v_dim = 128;
    const int qkv_dim = num_heads * k_dim;  // 2048
    const int qkv_total = qkv_dim * 3;      // 6144
    const int conv_kernel = 4;

    // Load reference data
    float* ref_x_normed = load_f32("/tmp/qwen35_ref_x_normed.f32", 1 * 4 * 1024);
    float* ref_mixed_qkv = load_f32("/tmp/qwen35_ref_mixed_qkv.f32", 1 * 6144 * 4);
    float* ref_conv_out = load_f32("/tmp/qwen35_ref_conv_out.f32", 1 * 6144 * 4);
    float* ref_query = load_f32("/tmp/qwen35_ref_query.f32", 1 * 4 * 16 * 128);
    float* ref_key = load_f32("/tmp/qwen35_ref_key.f32", 1 * 4 * 16 * 128);
    float* ref_value = load_f32("/tmp/qwen35_ref_value.f32", 1 * 4 * 16 * 128);
    float* ref_g = load_f32("/tmp/qwen35_ref_g.f32", 1 * 4 * 16);
    float* ref_beta = load_f32("/tmp/qwen35_ref_beta.f32", 1 * 4 * 16);
    float* ref_core_attn_out = load_f32("/tmp/qwen35_ref_core_attn_out.f32", 1 * 4 * 16 * 128);
    float* ref_normed_gated = load_f32("/tmp/qwen35_ref_normed_gated.f32", 64 * 128);
    float* ref_output = load_f32("/tmp/qwen35_ref_output.f32", 1 * 4 * 1024);
    float* ref_A_log = load_f32("/tmp/qwen35_ref_A_log.f32", 16);
    float* ref_dt_bias = load_f32("/tmp/qwen35_ref_dt_bias.f32", 16);
    float* ref_norm_weight = load_f32("/tmp/qwen35_ref_norm_weight.f32", 128);
    float* ref_conv1d_weight = load_f32("/tmp/qwen35_ref_conv1d_weight.f32", 6144 * 1 * 4);
    float* ref_in_proj_qkv = load_f32("/tmp/qwen35_ref_in_proj_qkv_weight.f32", 6144 * 1024);
    float* ref_in_proj_z = load_f32("/tmp/qwen35_ref_in_proj_z_weight.f32", 2048 * 1024);
    float* ref_in_proj_a = load_f32("/tmp/qwen35_ref_in_proj_a_weight.f32", 16 * 1024);
    float* ref_in_proj_b = load_f32("/tmp/qwen35_ref_in_proj_b_weight.f32", 16 * 1024);
    float* ref_out_proj = load_f32("/tmp/qwen35_ref_out_proj_weight.f32", 1024 * 2048);

    if (!ref_x_normed) { printf("Run dump_qwen35_ref.py first!\n"); return 1; }

    // ---- Step 1: Skip x_normed (just use ref directly) ----
    // HF: x_normed [batch, seq, hidden] = [1, 4, 1024]
    // mlllm matmul expects A in [M, K] row-major = [seq, hidden] = [4, 1024]
    // A[k + m*lda] where k=hidden, m=seq, lda=hidden
    // So A flat = [seq * hidden + hidden_idx] = row-major [seq, hidden]
    // HF flat = [seq * hidden + hidden_idx] — same!
    float* x_normed_ml = new float[hidden * seq_len];  // [4, 1024] row-major
    memcpy(x_normed_ml, ref_x_normed, hidden * seq_len * sizeof(float));

    // ---- Step 2: mixed_qkv = matmul(x_normed, in_proj_qkv_weight) ----
    // mlllm: A=[hidden, seq]=[1024,4], B=[N, K]=[6144, 1024]
    // matmul output: [N, seq] = [6144, 4]
    // HF: mixed_qkv = [1, 6144, 4] (batch, dim, seq) after transpose
    float* mixed_qkv_ml = new float[qkv_total * seq_len]();  // [6144, 4]
    {
        Tensor A = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                   hidden, seq_len, 1, 1, x_normed_ml);
        Tensor B = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                   qkv_total, hidden, 1, 1, ref_in_proj_qkv);
        Tensor C = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                   qkv_total, seq_len, 1, 1, mixed_qkv_ml);
        kernel_matmul_fp32(A, B, C, nullptr);
    }
    // Compare: HF mixed_qkv = [1, 6144, 4] → flat [6144, 4] = [dim, seq]
    // mlllm matmul writes C in [M, N] = [seq, dim] = [4, 6144] row-major
    // (C[m * N + n] = C[seq * 6144 + dim])
    // Need to transpose: ref[n*M+m] = mlllm[m*N+n]
    {
        int N = qkv_total, M = seq_len;
        float* tmp = new float[N * M];
        for (int n = 0; n < N; n++)
            for (int m = 0; m < M; m++)
                tmp[n * M + m] = mixed_qkv_ml[m * N + n];
        compare(ref_mixed_qkv, tmp, N * M, "mixed_qkv (matmul)");
        delete[] tmp;
    }

    // ---- Step 3: shortconv (no conv_state, zero-padded) ----
    // mlllm matmul output is [M, N] = [seq, dim] = [4, 6144] row-major
    // ShortConv expects [groups, seq] = [dim, seq] = [6144, 4]
    // Need to transpose: conv_in[g * seq + s] = mixed_qkv_ml[s * qkv_total + g]
    float* conv_in = new float[qkv_total * seq_len];  // [6144, 4] = [groups, seq]
    for (int g = 0; g < qkv_total; g++)
        for (int s = 0; s < seq_len; s++)
            conv_in[g * seq_len + s] = mixed_qkv_ml[s * qkv_total + g];

    // conv1d weight from HF: [6144, 1, 4] → reshape to [6144, 4]
    float* conv1d_w_flat = new float[6144 * 4];
    for (int g = 0; g < 6144; g++)
        for (int k = 0; k < 4; k++)
            conv1d_w_flat[g * 4 + k] = ref_conv1d_weight[g * 4 + k];

    float* conv_out_ml = new float[6144 * seq_len]();  // [6144, 4] = [groups, seq]
    {
        // Simulate ShortConv without conv_state (zero-padded)
        int kernel_size = 4;
        int groups = 6144;
        int prefix_len = kernel_size - 1;  // 3
        int total_len = prefix_len + seq_len;  // 7
        std::vector<float> stated(groups * total_len, 0.f);

        for (int g = 0; g < groups; g++) {
            const float* xs = conv_in + g * seq_len;
            float* dst = stated.data() + g * total_len + prefix_len;
            for (int s = 0; s < seq_len; s++) dst[s] = xs[s];
        }

        for (int g = 0; g < groups; g++) {
            const float* w = conv1d_w_flat + g * kernel_size;
            const float* st = stated.data() + g * total_len;
            float* ot = conv_out_ml + g * seq_len;
            for (int i = 0; i < seq_len; i++) {
                float sum = 0.f;
                int base = prefix_len + i;
                for (int k = 0; k < kernel_size; k++) {
                    int src_i = base - (kernel_size - 1) + k;
                    sum += st[src_i] * w[k];
                }
                float sig = 1.f / (1.f + expf(-sum));
                ot[i] = sum * sig;
            }
        }
    }
    // HF conv_out = [1, 6144, 4] → flat [6144, 4] = [dim, seq]
    // mlllm: [6144, 4] = [groups, seq] = [dim, seq] — same layout!
    compare(ref_conv_out, conv_out_ml, qkv_total * seq_len, "conv_out (shortconv)");

    // ---- Step 4: split qkv into q, k, v ----
    // conv_out is [6144, 4] = [dim, seq], split on dim=0:
    // q = conv_out[0:2048], k = conv_out[2048:4096], v = conv_out[4096:6144]
    // Each is [2048, 4] = [dim, seq]
    //
    // GDN kernel expects q/k: [head, seq, k_dim] (q_h = q + h*(seq*k_dim), q_t = q_h + t*k_dim)
    // GDN kernel expects v: [head, seq, v_dim] (same layout)
    float* q_ml = new float[num_heads * seq_len * k_dim]();  // [16, 4, 128]
    float* k_ml = new float[num_heads * seq_len * k_dim]();
    float* v_ml = new float[num_heads * seq_len * v_dim]();

    for (int s = 0; s < seq_len; s++)
        for (int h = 0; h < num_heads; h++)
            for (int d = 0; d < k_dim; d++) {
                int q_dim_idx = h * k_dim + d;
                int k_dim_idx = qkv_dim + h * k_dim + d;
                int v_dim_idx = 2 * qkv_dim + h * v_dim + d;
                // GDN layout: [head, seq, k_dim] = h * (seq * k_dim) + s * k_dim + d
                int ml_idx = h * (seq_len * k_dim) + s * k_dim + d;
                q_ml[ml_idx] = conv_out_ml[q_dim_idx * seq_len + s];
                k_ml[ml_idx] = conv_out_ml[k_dim_idx * seq_len + s];
                v_ml[ml_idx] = conv_out_ml[v_dim_idx * seq_len + s];
            }

    // Also compare q/k/v with HF reference
    // HF query: [1, 4, 16, 128] → flat [seq * (heads*dim) + head * dim + d]
    // But HF query comes from conv_out split, which is after L2 norm in the GDN kernel.
    // Our ref_query is AFTER L2 norm. Let's compare after GDN instead.

    // ---- Step 5: g = -exp(A_log) * softplus(a + dt_bias) ----
    // HF: g = [1, 4, 16] = [batch, seq, heads]
    // mlllm: g = [num_heads, seq] = [16, 4]
    // mlllm g_h = g_data + h * seq_len → g[head, seq]
    // So: ml_g[h * seq + s] = hf_g[s * num_heads + h]
    float* g_ml = new float[num_heads * seq_len]();  // [16, 4]
    for (int s = 0; s < seq_len; s++)
        for (int h = 0; h < num_heads; h++)
            g_ml[h * seq_len + s] = ref_g[s * num_heads + h];

    // ---- Step 6: beta = sigmoid(b) ----
    float* beta_ml = new float[num_heads * seq_len]();  // [16, 4]
    for (int s = 0; s < seq_len; s++)
        for (int h = 0; h < num_heads; h++)
            beta_ml[h * seq_len + s] = ref_beta[s * num_heads + h];

    // ---- Step 7: GDN recurrence ----
    // First verify L2 norm: compute L2 norm of q/k in C++ and compare with Python
    {
        // Python l2norm: q_norm[d] = q_pre[d] / sqrt(sum(q_pre^2) + 1e-6)
        // q_ml is [head, seq, k_dim] = [16, 4, 128], pre-norm
        // Check head 0, seq 0
        float q_sum_sq = 0;
        for (int d = 0; d < k_dim; d++) {
            int ml_idx = 0 * (seq_len * k_dim) + 0 * k_dim + d;
            q_sum_sq += q_ml[ml_idx] * q_ml[ml_idx];
        }
        float q_inv_norm = 1.0f / sqrtf(q_sum_sq + 1e-6f);
        printf("  L2 norm q[head=0,seq=0]: sum_sq=%e inv_norm=%e\n", q_sum_sq, q_inv_norm);
        printf("  q_norm[0,0,0:3]: ");
        for (int d = 0; d < 3; d++) {
            int ml_idx = 0 * (seq_len * k_dim) + 0 * k_dim + d;
            printf("%e ", q_ml[ml_idx] * q_inv_norm);
        }
        printf("\n");
        // Python ref: q_pre[0,0,0:3] * inv_norm
        // ref_query is pre-norm, so we need to compute norm ourselves
        // Actually let's just check: does the GDN kernel's L2 norm produce
        // the same result as our manual calculation?
    }

    // State: [v_dim, k_dim, num_heads] = [128, 128, 16], init to zero
    float* state_ml = new float[k_dim * v_dim * num_heads]();  // [128, 128, 16]
    float* out_ml = new float[v_dim * seq_len * num_heads]();   // [128, 4, 16]

    {
        Tensor q_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                     k_dim, seq_len, num_heads, 1, q_ml);
        Tensor k_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                     k_dim, seq_len, num_heads, 1, k_ml);
        Tensor v_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                     v_dim, seq_len, num_heads, 1, v_ml);
        Tensor g_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                     seq_len, num_heads, 1, 1, g_ml);
        Tensor beta_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                        seq_len, num_heads, 1, 1, beta_ml);
        Tensor state_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                         v_dim, k_dim, num_heads, 1, state_ml);
        Tensor out_t = Tensor::create(Precision::FP32, MemoryType::EXTERNAL,
                                       v_dim, seq_len, num_heads, 1, out_ml);

        OpParams params;
        params.i32 = {num_heads, k_dim, v_dim, 1};  // use_qk_l2norm=1
        std::vector<const Tensor*> inputs = {&q_t, &k_t, &v_t, &g_t, &beta_t, &state_t};
        std::vector<Tensor*> outputs = {&out_t};
        kernel_gdn_prefill(params, inputs, outputs, nullptr);
    }

    // Debug: print head=0, seq=0 intermediate values
    printf("\n  Debug head=0 seq=0:\n");
    printf("  q_ml[0:3] = %.8e %.8e %.8e\n", q_ml[0], q_ml[1], q_ml[2]);
    printf("  k_ml[0:3] = %.8e %.8e %.8e\n", k_ml[0], k_ml[1], k_ml[2]);
    printf("  v_ml[0:3] = %.8e %.8e %.8e\n", v_ml[0], v_ml[1], v_ml[2]);
    printf("  g_ml[0] = %.8e\n", g_ml[0]);
    printf("  beta_ml[0] = %.8e\n", beta_ml[0]);
    // After L2 norm (compute manually)
    float q_ss = 0; for (int d = 0; d < k_dim; d++) q_ss += q_ml[d]*q_ml[d];
    float q_inv = 1.0f/sqrtf(q_ss + 1e-6f);
    float k_ss = 0; for (int d = 0; d < k_dim; d++) k_ss += k_ml[d]*k_ml[d];
    float k_inv = 1.0f/sqrtf(k_ss + 1e-6f);
    printf("  q_norm[0:3] = %.8e %.8e %.8e\n", q_ml[0]*q_inv, q_ml[1]*q_inv, q_ml[2]*q_inv);
    printf("  k_norm[0:3] = %.8e %.8e %.8e\n", k_ml[0]*k_inv, k_ml[1]*k_inv, k_ml[2]*k_inv);
    // Manual GDN for head=0, seq=0
    {
        float scale = 1.0f / sqrtf((float)k_dim);
        float g_exp = expf(g_ml[0]);
        float beta_t = beta_ml[0];
        // state is all zeros, so kv_mem = 0, delta = v * beta
        // state = outer(k_norm, v * beta)
        // out = state.T @ q_norm * scale = (k_norm . q_norm) * v * beta * scale
        float dot = 0;
        for (int d = 0; d < k_dim; d++) dot += q_ml[d]*q_inv * k_ml[d]*k_inv;
        printf("  k_norm . q_norm = %.8e\n", dot);
        printf("  manual out[0:3] = %.8e %.8e %.8e\n",
               dot * v_ml[0] * beta_t * scale,
               dot * v_ml[1] * beta_t * scale,
               dot * v_ml[2] * beta_t * scale);
        printf("  kernel out[0:3] = %.8e %.8e %.8e\n",
               out_ml[0], out_ml[1], out_ml[2]);
        // ref
        printf("  ref out[0:3]    = %.8e %.8e %.8e\n",
               ref_core_attn_out[0], ref_core_attn_out[1], ref_core_attn_out[2]);
    }

    // Compare GDN output — also check per-seq error
    // HF core_attn_out: [1, 4, 16, 128] = [batch, seq, heads, head_dim]
    // kernel output: [head, seq, v_dim] = [16, 4, 128]
    // HF expects: [seq, heads, v_dim] = [4, 16, 128]
    float* out_hf_layout = new float[seq_len * num_heads * v_dim]();
    for (int s = 0; s < seq_len; s++)
        for (int h = 0; h < num_heads; h++)
            for (int d = 0; d < v_dim; d++) {
                int ml_idx = h * (seq_len * v_dim) + s * v_dim + d;
                int hf_idx = s * (num_heads * v_dim) + h * v_dim + d;
                out_hf_layout[hf_idx] = out_ml[ml_idx];
            }
    printf("  out_ml[0:3]     = %.8e %.8e %.8e\n", out_ml[0], out_ml[1], out_ml[2]);
    printf("  out_hf[0:3]     = %.8e %.8e %.8e\n", out_hf_layout[0], out_hf_layout[1], out_hf_layout[2]);
    printf("  ref[0:3]        = %.8e %.8e %.8e\n", ref_core_attn_out[0], ref_core_attn_out[1], ref_core_attn_out[2]);

    // Per-seq comparison
    for (int s = 0; s < seq_len; s++) {
        float max_err = 0;
        int max_idx = 0;
        int offset = s * num_heads * v_dim;
        for (int i = 0; i < num_heads * v_dim; i++) {
            float err = fabsf(ref_core_attn_out[offset + i] - out_hf_layout[offset + i]);
            if (err > max_err) { max_err = err; max_idx = i; }
        }
        printf("  seq=%d: max_err=%e at head=%d dim=%d (ref=%e got=%e)\n",
               s, max_err, max_idx / v_dim, max_idx % v_dim,
               ref_core_attn_out[offset + max_idx], out_hf_layout[offset + max_idx]);
    }
    compare(ref_core_attn_out, out_hf_layout, seq_len * num_heads * v_dim, "core_attn_out (GDN)");

    // Print first few values for debugging
    printf("\n  GDN ref[0,0,0,:5]: ");
    for (int i = 0; i < 5; i++) printf("%.8e ", ref_core_attn_out[i]);
    printf("\n  GDN mlllm[0,0,0,:5]: ");
    for (int i = 0; i < 5; i++) printf("%.8e ", out_hf_layout[i]);
    printf("\n");

    // ---- Cleanup ----
    delete[] ref_x_normed; delete[] ref_mixed_qkv; delete[] ref_conv_out;
    delete[] ref_query; delete[] ref_key; delete[] ref_value;
    delete[] ref_g; delete[] ref_beta; delete[] ref_core_attn_out;
    delete[] ref_normed_gated; delete[] ref_output;
    delete[] ref_A_log; delete[] ref_dt_bias; delete[] ref_norm_weight;
    delete[] ref_conv1d_weight; delete[] ref_in_proj_qkv; delete[] ref_in_proj_z;
    delete[] ref_in_proj_a; delete[] ref_in_proj_b; delete[] ref_out_proj;
    delete[] x_normed_ml; delete[] mixed_qkv_ml; delete[] conv_out_ml;
    delete[] conv1d_w_flat; delete[] q_ml; delete[] k_ml; delete[] v_ml;
    delete[] g_ml; delete[] beta_ml; delete[] state_ml; delete[] out_ml;
    delete[] out_hf_layout;

    printf(failures ? "\n%d FAILED\n" : "\nAll comparisons passed!\n", failures);
    return failures;
}
